import os
import re
from flask import Flask, send_from_directory, abort
from werkzeug.utils import secure_filename

app = Flask(__name__)
UPLOAD_FOLDER = 'uploads'
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

def is_valid_filename(filename):
    """Validate filename to prevent path traversal and ensure backward compatibility"""
    if not filename:
        return False
    
    # Check for path traversal attempts
    if '..' in filename or filename.startswith('/'):
        return False
    
    # Allow only alphanumeric, dots, underscores, hyphens, and spaces
    if not re.match(r'^[a-zA-Z0-9._ -]+$', filename):
        return False
    
    return True

def get_legacy_filename(filename):
    """Convert modern filename to legacy format if needed"""
    # This function can be extended to handle specific legacy naming patterns
    return filename

@app.route('/legacy/<path:filename>')
def legacy_static(filename):
    """Serve static files with legacy support"""
    # Validate filename
    if not is_valid_filename(filename):
        abort(400)
    
    # Get legacy filename
    legacy_filename = get_legacy_filename(filename)
    
    # Secure the filename
    safe_filename = secure_filename(legacy_filename)
    
    # Ensure we're only serving files from uploads directory
    try:
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], safe_filename)
        # Verify the file exists and is within the uploads directory
        if not os.path.exists(file_path):
            abort(404)
        
        # Check if file is within the allowed directory
        if not os.path.abspath(file_path).startswith(os.path.abspath(app.config['UPLOAD_FOLDER'])):
            abort(403)
            
        return send_from_directory(app.config['UPLOAD_FOLDER'], safe_filename)
    except Exception:
        abort(404)

